/**
 * Parse an XML string as an AAS instance.
 *
 * @param xml - XML string to parse
 * @returns parsed AAS instance or an error
 */
export function fromXmlString(
  xml: string
): AasCommon.Either<AasTypes.Class, DeserializationError> {
  if (xml.length === 0) {
    return newDeserializationError<AasTypes.Class>(
      "Expected an XML document, but got an empty string"
    );
  }

  const tokensOrError = tokenizeXml(xml);
  if (tokensOrError.error !== null) {
    return new AasCommon.Either<AasTypes.Class, DeserializationError>(
      null,
      tokensOrError.error
    );
  }

  const cursor = new XmlCursor(tokensOrError.mustValue());

  const rootOpenTagOrError = readRequiredRootOpenTag(cursor);
  if (rootOpenTagOrError.error !== null) {
    return new AasCommon.Either<AasTypes.Class, DeserializationError>(
      null,
      rootOpenTagOrError.error
    );
  }

  const rootOpenTag = rootOpenTagOrError.mustValue();
  const rootLocalName = localNameOfTag(rootOpenTag.tag);

  const dispatch = ROOT_DISPATCH_BY_LOCAL_NAME.get(rootLocalName);
  if (dispatch === undefined) {
    return newDeserializationError<AasTypes.Class>(
      `Unexpected root XML element: ${rootLocalName}`
    );
  }

  const instanceOrError = dispatch(cursor, rootOpenTag);
  if (instanceOrError.error !== null) {
    return instanceOrError;
  }

  cursor.skipIgnorable();
  const tokenAfterInstance = cursor.current();
  if (tokenAfterInstance !== null) {
    if (!(tokenAfterInstance instanceof CloseTagToken)) {
      return newDeserializationError<AasTypes.Class>(
        "Expected root closing XML element, but got token kind: " +
        currentTokenKind(cursor)
      );
    }

    const closeError = checkExpectedCloseTag(
      tokenAfterInstance,
      rootLocalName
    );
    if (closeError !== null) {
      return new AasCommon.Either<AasTypes.Class, DeserializationError>(
        null,
        closeError
      );
    }

    cursor.advance();
  }

  cursor.skipIgnorable();
  if (cursor.current() !== null) {
    return newDeserializationError<AasTypes.Class>(
      "Expected no tokens after the root XML element, but got token kind: " +
        currentTokenKind(cursor)
    );
  }

  return instanceOrError;
}

type SerializedElement = {
  localName: string;
  innerXml: string;
};

function openTag(localName: string, withNamespace = false): string {
  if (withNamespace) {
    return `<${localName} xmlns="${NAMESPACE}">`;
  }

  return `<${localName}>`;
}

function closeTag(localName: string): string {
  return `</${localName}>`;
}

function escapeXmlText(text: string): string {
  return text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");
}

function serializeBooleanText(value: boolean): string {
  return value ? "true" : "false";
}

function serializeIntegerText(value: number): string {
  if (!Number.isInteger(value)) {
    throw new Error(`Expected an integer, but got: ${value}`);
  }

  return `${value}`;
}

function serializeFloatText(value: number): string {
  if (Number.isNaN(value)) {
    return "NaN";
  }
  if (value === Infinity) {
    return "INF";
  }
  if (value === -Infinity) {
    return "-INF";
  }

  return `${value}`;
}

function serializeStringText(value: string): string {
  return escapeXmlText(value);
}

function serializeBase64EncodedBytesText(value: Uint8Array): string {
  return escapeXmlText(AasCommon.base64Encode(value));
}

